    payload: Dict[str, Any] = {
        'status': 'submitted',
        'tx_signature': tx_signature,
        'send_phase': send_phase,
        'submitted_at': datetime.now(timezone.utc),
        'completed_at': None,
        'last_error': None,
        'retry_after': None,
    }
    if amount_token is not None:
